import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';
import { useIntl } from 'react-intl';

import { PresetItem } from './PresetItem.js';
import * as styles from './Presets.sty.js';
import { Divider } from '../../../../layouts/divider/Divider.js';
import { Text } from '../../../../typography/text/Text.js';
import { TIMEFRAME_SELECTOR_MESSAGES } from '../../constants/timeframeSelectorMessages.js';
import { PresetItemContext } from '../../contexts/PresetItemContext.js';
import { getTimeframePresets } from '../../utils/presets-helpers.js';
import {
  timeframeQueryClient,
  TIMEFRAME_PRESETS_QUERY_KEY,
} from '../../utils/TimeframePresetsClient.js';

/**
 * A list of recently selected timeframes shown in the overlay.
 * @public
 */
export const RecentTimeframes = () => {
  const intl = useIntl();

  const { data, isLoading } = useQuery(
    {
      queryKey: TIMEFRAME_PRESETS_QUERY_KEY,
      queryFn: getTimeframePresets,
      notifyOnChangeProps: ['dataUpdatedAt'],
    },
    timeframeQueryClient,
  );

  const presetItemContextValue = useMemo(
    () => ({ isRecent: true as const }),
    [],
  );

  if (!data?.recentPresets?.length || isLoading) {
    return null;
  }

  const ariaLabel = intl.formatMessage(
    TIMEFRAME_SELECTOR_MESSAGES.recentTimeframesList,
  );

  return (
    <>
      <Divider flexItem={false} />
      <div>
        <Text textStyle="small" className={styles.recentHeading} as="div">
          {intl.formatMessage(
            TIMEFRAME_SELECTOR_MESSAGES.recentTimeframesHeading,
          )}
        </Text>
        <ul
          role="listbox"
          className={styles.listContainer}
          aria-label={ariaLabel}
        >
          <PresetItemContext.Provider value={presetItemContextValue}>
            {data.recentPresets.map(({ timeframe }, index) => (
              <PresetItem
                key={`${timeframe.from} → ${timeframe.to}`}
                value={timeframe}
                data-dt-name="Recent"
                data-dt-properties={`index:${index},valueFrom:${timeframe.from},valueTo:${timeframe.to}`}
              />
            ))}
          </PresetItemContext.Provider>
        </ul>
      </div>
    </>
  );
};

(
  RecentTimeframes as typeof RecentTimeframes & { displayName: string }
).displayName = 'RecentTimeframes';
